fn main () -> ExitCode { let mut mode = Mode :: Stdout ; let mut flatten = false ; let mut readable = false ; let mut expand_spine = false ; let mut explain = false ; let mut config : Option < String > = None ; let mut paths : Vec < String > = Vec :: new () ; let mut args = Args :: from_env () ; while let Some (a) = args . next () { match a . as_str () { "--check" => mode = Mode :: Check , "--write" => mode = Mode :: Write , "--flatten" => flatten = true , "--readable" => readable = true , "--expand-spine" => expand_spine = true , "--explain" => explain = true , "--config" => match args . value () { Some (p) => config = Some (p) , None => return usage () , } , "-" => paths . push ("-" . to_owned ()) , s if s . starts_with ("--") => return usage () , s => paths . push (s . to_owned ()) , } } if paths . is_empty () { return usage () ; } if mode == Mode :: Write && paths . iter () . any (| p | p == "-") { eprintln ! ("mycfmt: --write cannot rewrite stdin; use the default (stdout) for `-`") ; return usage () ; } if flatten && mode == Mode :: Write { eprintln ! ("mycfmt: --flatten cannot be used with --write; the stream form is stdout-only \
             (pipe it to a file if needed)") ; return usage () ; } if flatten && readable { eprintln ! ("mycfmt: --flatten and --readable are mutually exclusive (opposite layout postures) — \
             pick one") ; return usage () ; } if expand_spine && ! readable { eprintln ! ("mycfmt: --expand-spine is a --readable house-style knob (M-976) — it requires --readable") ; return usage () ; } let pin = match resolve_pin (config . as_deref () , & paths) { Ok (p) => p , Err (code) => return code , } ; let mut worst = 0u8 ; for path in & paths { let code = run_one (path , mode , flatten , readable , expand_spine , explain , pin . as_deref () ,) ; worst = worst . max (code) ; } ExitCode :: from (worst) }
